// Handle missing values
if (!msg.payload.temp) msg.payload.temp = 20;
if (!msg.payload.rain_1h) msg.payload.rain_1h = 0;
if (!msg.payload.traffic_volume) return null;

// Remove noise (no negative values)
msg.payload.traffic_volume = Math.max(0, msg.payload.traffic_volume);

return msg;

// Convert date
let date = new Date(msg.payload.date_time);

// Extract hour
msg.payload.hour = date.getHours();

// Create peak hour feature
// Used 1 and 0 to replace True & False
msg.payload.is_peak = (msg.payload.hour >= 7 && msg.payload.hour <= 9) || 
                      (msg.payload.hour >= 16 && msg.payload.hour <= 18) ? 1 : 0;

// Day of week
// 0 - Sunday, 6 - Saturday
msg.payload.day_of_week = date.getDay();

// Traffic Level
// Low (0), Medium (1), High (2)
let volume = msg.payload.traffic_volume;
if (volume < 1500) {
    msg.payload.traffic_level = 0; // Low
} else if (volume < 4500) {
    msg.payload.traffic_level = 1; // Medium
} else {
    msg.payload.traffic_level = 2; // High
}

return msg;

let p = msg.payload;
msg.payload = `${p.date_time},${p.traffic_volume},${p.temp},${p.rain_1h},${p.hour},${p.is_peak},${p.day_of_week},${p.traffic_level}\n`;
return msg;

// Handle missing values
if (!msg.payload.temp) msg.payload.temp = 20;
if (!msg.payload.rain_1h) msg.payload.rain_1h = 0;

// Remove invalid data
if (!msg.payload.traffic_volume) return null;
msg.payload.traffic_volume = Math.max(0, msg.payload.traffic_volume);

return msg;

let date = new Date(msg.payload.date_time);

// Extract hour
msg.payload.hour = date.getHours();

// Peak hour
msg.payload.is_peak = (msg.payload.hour >= 7 && msg.payload.hour <= 9) ||
    (msg.payload.hour >= 16 && msg.payload.hour <= 18);

// Normalize
msg.payload.traffic_scaled = msg.payload.traffic_volume / 10000;

return msg;
